import{_ as a,o as i,c as s,ag as t}from"./chunks/framework.ePeAWSvT.js";const u=JSON.parse('{"title":"Troubleshooting","description":"Common Foldergram issues and the exact implementation details behind them.","frontmatter":{"title":"Troubleshooting","description":"Common Foldergram issues and the exact implementation details behind them."},"headers":[],"relativePath":"troubleshooting.md","filePath":"troubleshooting.md","lastUpdated":1774719654000}'),r={name:"troubleshooting.md"};function n(o,e,l,d,p,h){return i(),s("div",null,[...e[0]||(e[0]=[t(`<h1 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h1><h2 id="the-app-says-the-library-storage-is-unavailable" tabindex="-1">The app says the library storage is unavailable <a class="header-anchor" href="#the-app-says-the-library-storage-is-unavailable" aria-label="Permalink to &quot;The app says the library storage is unavailable&quot;">​</a></h2><p>Foldergram checks the configured:</p><ul><li>gallery directory</li><li>thumbnails directory</li><li>previews directory</li></ul><p>If any of those are unavailable, the UI reports the reason exposed by the backend.</p><p>Check:</p><ul><li>the configured paths in <code>.env</code></li><li>whether those paths exist</li><li>whether they are writable by the current process</li></ul><h2 id="the-database-keeps-resetting" tabindex="-1">The database keeps resetting <a class="header-anchor" href="#the-database-keeps-resetting" aria-label="Permalink to &quot;The database keeps resetting&quot;">​</a></h2><p>If <code>DB_DIR</code> is unavailable, Foldergram falls back to an in-memory SQLite database. That means indexed state disappears when the process stops.</p><p>Fix the configured database directory first.</p><h2 id="nothing-is-being-indexed" tabindex="-1">Nothing is being indexed <a class="header-anchor" href="#nothing-is-being-indexed" aria-label="Permalink to &quot;Nothing is being indexed&quot;">​</a></h2><p>Start with the gallery structure rules:</p><ul><li>files directly inside <code>GALLERY_ROOT</code> are ignored</li><li>hidden folders are ignored</li><li>a folder is indexed only when it directly contains supported media</li></ul><p>This will not be indexed:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>gallery/</span></span>
<span class="line"><span>  loose-file.jpg</span></span>
<span class="line"><span>  trips/</span></span>
<span class="line"><span>    oslo/</span></span>
<span class="line"><span>      notes.txt</span></span></code></pre></div><p>This will be indexed:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>gallery/</span></span>
<span class="line"><span>  trips/</span></span>
<span class="line"><span>    oslo/</span></span>
<span class="line"><span>      IMG_0001.jpg</span></span></code></pre></div><h2 id="rescan-returns-a-rebuild-required-message" tabindex="-1">Rescan returns a rebuild-required message <a class="header-anchor" href="#rescan-returns-a-rebuild-required-message" aria-label="Permalink to &quot;Rescan returns a rebuild-required message&quot;">​</a></h2><p>This happens when the configured gallery root changed after a prior successful library index already existed.</p><p>Use Settings or <code>POST /api/admin/rebuild-index</code> to rebuild the library against the new root.</p><h2 id="moments-are-missing-and-highlights-appear-instead" tabindex="-1">Moments are missing and highlights appear instead <a class="header-anchor" href="#moments-are-missing-and-highlights-appear-instead" aria-label="Permalink to &quot;Moments are missing and highlights appear instead&quot;">​</a></h2><p>That is expected when the library does not have enough EXIF-backed timestamps.</p><p>Foldergram switches to Highlights unless it has:</p><ul><li>at least <code>24</code> indexed posts</li><li>at least <code>18</code> EXIF-backed posts</li><li>at least <code>30%</code> EXIF coverage</li></ul><h2 id="a-folder-named-stories-stopped-appearing-as-a-normal-album" tabindex="-1">A folder named <code>stories</code> stopped appearing as a normal album <a class="header-anchor" href="#a-folder-named-stories-stopped-appearing-as-a-normal-album" aria-label="Permalink to &quot;A folder named \`stories\` stopped appearing as a normal album&quot;">​</a></h2><p>That is expected when Foldergram is using the default reserved-stories mode.</p><p>In that mode, <code>AppFolder/stories</code> is reinterpreted as folder-story data instead of a standalone app folder.</p><p>If you want folders literally named <code>stories</code> to remain ordinary app folders:</p><ol><li>open Settings</li><li>enable <code>Treat stories folders as normal app folders</code></li><li>save the change and let the library rescan</li></ol><h2 id="videos-fail-to-index-or-generate-previews" tabindex="-1">Videos fail to index or generate previews <a class="header-anchor" href="#videos-fail-to-index-or-generate-previews" aria-label="Permalink to &quot;Videos fail to index or generate previews&quot;">​</a></h2><p>Check that both tools are installed and available on <code>PATH</code>:</p><ul><li><code>ffprobe</code></li><li><code>ffmpeg</code></li></ul><p>Foldergram uses them directly for supported video files.</p><h2 id="a-video-opens-from-the-original-file-instead-of-a-generated-preview" tabindex="-1">A video opens from the original file instead of a generated preview <a class="header-anchor" href="#a-video-opens-from-the-original-file-instead-of-a-generated-preview" aria-label="Permalink to &quot;A video opens from the original file instead of a generated preview&quot;">​</a></h2><p>That is a normal optimization. Foldergram streams the original file directly when the video is already suitable for browser playback under the current size and codec rules.</p><p>See <a href="/media-processing">Media Processing</a> for the exact conditions.</p><h2 id="the-development-watcher-is-not-reacting" tabindex="-1">The development watcher is not reacting <a class="header-anchor" href="#the-development-watcher-is-not-reacting" aria-label="Permalink to &quot;The development watcher is not reacting&quot;">​</a></h2><p>The watcher is not a permanent always-on background process for every startup path. It is development-only and is started by the scan and rebuild flows.</p><p>If needed:</p><ol><li>run a manual scan from Settings</li><li>make your filesystem change again</li></ol><h2 id="likes-disappeared-after-a-rebuild" tabindex="-1">Likes disappeared after a rebuild <a class="header-anchor" href="#likes-disappeared-after-a-rebuild" aria-label="Permalink to &quot;Likes disappeared after a rebuild&quot;">​</a></h2><p>That is expected for <code>Rebuild Library Index</code>. The rebuild resets the indexed library tables, including <code>likes</code>.</p><p>Thumbnail-only rebuilds do not clear likes.</p><h2 id="docs-build-fails" tabindex="-1">Docs build fails <a class="header-anchor" href="#docs-build-fails" aria-label="Permalink to &quot;Docs build fails&quot;">​</a></h2><p>Use the root command:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build:docs</span></span></code></pre></div><p>If it fails, check for:</p><ul><li>broken internal links</li><li>invalid frontmatter</li><li>mistakes in <code>docs/.vitepress/config.ts</code></li></ul><h2 id="the-app-still-behaves-oddly-in-development-after-frontend-changes" tabindex="-1">The app still behaves oddly in development after frontend changes <a class="header-anchor" href="#the-app-still-behaves-oddly-in-development-after-frontend-changes" aria-label="Permalink to &quot;The app still behaves oddly in development after frontend changes&quot;">​</a></h2><p>The client actively unregisters previously installed service workers in development. Reload once after startup if you previously visited a production build from the same origin and the browser still has stale cached assets.</p>`,50)])])}const b=a(r,[["render",n]]);export{u as __pageData,b as default};
